class Solution:
    def heapifyInsertion(self, nums: list[int], n: int, idx: int) -> list[int]:
        for i in range(n - 1, idx, -1):
            nums[i], nums[i - 1] = nums[i - 1], nums[i]
        self.max_heapify(nums, n - 1)
        return nums

    def max_heapify(self, nums: list[int], i: int) -> None:
        largest = i
        left = 2 * i + 1
        right = 2 * i + 2
        if left < n and nums[left] > nums[largest]:
            largest = left
        if right < n and nums[right] > nums[largest]:
            largest = right
        if largest != i:
            nums[i], nums[largest] = nums[largest], nums[i]
            self.max_heapify(nums, largest)

    def heapifyInsertion2(self, nums: list[int], n: int, idx: int) -> list[int]:
