class Solution {
public:
    vector<int> heapifyInsertion(vector<int> array, int n, int idx) {
        for (int i = n - 1; i > idx; --i)
            swap(array[i], array[i - 1]);

        int root = n - 1;
        while (root > 0) {
            int largest = root;
            int left = 2 * root + 1;
            int right = 2 * root + 2;
            if (left < n && array[left] > array[largest])
                largest = left;
            if (right < n && array[right] > array[largest])
                largest = right;
            if (largest != root) {
                swap(array[root], array[largest]);
                root = largest;
            } else
                break;
        }

        return array;
    }
};
